class LoginEkrani(tk.Toplevel):
    def __init__(self, master, on_login):
        super().__init__(master)
        self.on_login = on_login
        self.title("İstanbul Metro — Giriş")
        self.geometry("900x580")
        self.resizable(False, False)
        self.configure(bg=BG)
        self.grab_set()
        self._yukle_resim()
        self._olustur()
        self.after(50, self._animate_in)

    def _yukle_resim(self):
        raw = base64.b64decode(KIZ_KULESI_B64)
        img = Image.open(io.BytesIO(raw)).convert("RGB")
        # Kız Kulesi fotoğrafını pencere boyutuna ölçekle
        img = img.resize((900, 580), Image.LANCZOS)
        # Karartma overlay
        overlay = Image.new("RGB", (900, 580), (5, 8, 22))
        img = Image.blend(img, overlay, 0.48)
        # Sol tarafa ekstra karartma (form alanı)
        grad = Image.new("RGBA", (900, 580), (0,0,0,0))
        draw = ImageDraw.Draw(grad)
        for i in range(450):
            alpha = int(200 * (1 - i/450))
            draw.rectangle([900-450+i, 0, 900-450+i+1, 580], fill=(5,8,22,alpha))
        img_rgba = img.convert("RGBA")
        img_rgba = Image.alpha_composite(img_rgba, grad)
        self.bg_photo = ImageTk.PhotoImage(img_rgba.convert("RGB"))

    def _olustur(self):
        # Arka plan canvas
        self.canvas = tk.Canvas(self, width=900, height=580, highlightthickness=0)
        self.canvas.pack(fill="both", expand=True)
        self.canvas.create_image(0, 0, image=self.bg_photo, anchor="nw")

        # Kız Kulesi altyazı
        self.canvas.create_text(240, 520, text="Kız Kulesi — İstanbul Boğazı",
            font=("Helvetica", 10, "italic"), fill="#c9a84c", anchor="center")

        # Sağ panel - form kutusu
        panel = tk.Frame(self.canvas, bg=PANEL_BG, bd=0)
        self.canvas.create_window(680, 290, window=panel, width=330, height=460)

        # Altın çerçeve efekti için ince canvas çizgisi
        self.canvas.create_rectangle(514, 58, 846, 522,
            outline=GOLD_D, width=1)

        # Logo alanı
        logo_f = tk.Frame(panel, bg=PANEL_BG)
        logo_f.pack(pady=(32,0))

        # Metro simgesi (canvas içinde)
        lc = tk.Canvas(logo_f, width=56, height=56, bg=PANEL_BG, highlightthickness=0)
        lc.pack()
        lc.create_oval(3,3,53,53, outline=GOLD, width=2, fill="#12192e")
        lc.create_rectangle(8,24,48,32, fill=GOLD, outline="")
        lc.create_oval(11,20,23,36, fill=GOLD, outline="")
        lc.create_oval(33,20,45,36, fill=GOLD, outline="")
        lc.create_oval(14,24,20,32, fill=PANEL_BG, outline="")
        lc.create_oval(36,24,42,32, fill=PANEL_BG, outline="")
        lc.create_rectangle(26,12,30,44, fill=GOLD, outline="")

        tk.Label(panel, text="İSTANBUL METRO", bg=PANEL_BG,
            fg=GOLD_L, font=("Georgia", 15, "bold")).pack(pady=(10,2))
        tk.Label(panel, text="AKILLI ULAŞIM SİSTEMİ", bg=PANEL_BG,
            fg=TEXT_M, font=("Helvetica", 8), letter_spacing=3).pack()

        # Ayraç
        sep = tk.Frame(panel, bg=GOLD_D, height=1)
        sep.pack(fill="x", padx=30, pady=18)

        # Form
        form = tk.Frame(panel, bg=PANEL_BG)
        form.pack(padx=30, fill="x")

        tk.Label(form, text="KULLANICI ADI", bg=PANEL_BG,
            fg=GOLD_D, font=("Helvetica", 8)).pack(anchor="w")
        self.kullanici_var = tk.StringVar(value="aasd")
        self.kullanici_entry = self._entry(form, self.kullanici_var)
        self.kullanici_entry.pack(fill="x", pady=(4,12))

        tk.Label(form, text="ŞİFRE", bg=PANEL_BG,
            fg=GOLD_D, font=("Helvetica", 8)).pack(anchor="w")
        self.sifre_var = tk.StringVar(value="1234")
        self.sifre_entry = self._entry(form, self.sifre_var, show="●")
        self.sifre_entry.pack(fill="x", pady=(4,4))
        self.sifre_entry.bind("<Return>", lambda e: self._giris())

        self.hata_lbl = tk.Label(form, text="", bg=PANEL_BG,
            fg="#e74c3c", font=("Helvetica", 9))
        self.hata_lbl.pack(pady=4)

        giris_btn = tk.Button(form, text="SİSTEME GİRİŞ YAP",
            bg=GOLD, fg=BG, font=("Helvetica", 11, "bold"),
            relief="flat", cursor="hand2", pady=10,
            activebackground=GOLD_L, activeforeground=BG,
            command=self._giris)
        giris_btn.pack(fill="x", pady=8)

        tk.Label(panel, text="Demo: aasd / 1234", bg=PANEL_BG,
            fg=TEXT_M, font=("Helvetica", 9)).pack(pady=(0,20))

    def _entry(self, parent, var, show=None):
        e = tk.Entry(parent, textvariable=var,
            bg="#12192e", fg=TEXT, insertbackground=GOLD,
            relief="flat", font=("Helvetica", 12),
            highlightthickness=1, highlightcolor=GOLD,
            highlightbackground=GOLD_D,
            bd=8)
        if show:
            e.configure(show=show)
        return e

    def _giris(self):
        u = self.kullanici_var.get().strip()
        p = self.sifre_var.get().strip()
        if u in KULLANICILAR and KULLANICILAR[u]["sifre"] == p:
            self.hata_lbl.config(text="")
            self.destroy()
            self.on_login(u)
        else:
            self.hata_lbl.config(text="✗  Kullanıcı adı veya şifre hatalı!")
            self.sifre_entry.delete(0, "end")

    def _animate_in(self):
        pass  # Tkinter popup penceresi doğal animasyona sahip


